177→/**
178→ * Find the best matching method in a method table for the given args.
179→ * Scoring: Val match (1000) > exact type (100) > subtype (10) > any (1)
180→ */
181→fn Value* find_best_method(MethodTable* mt, Value*[] args, Interp* interp) {
182→    long best_score = -1;
183→    Value* best_method = null;
184→    usz best_count = 0;
185→
186→    // Pre-compute arg TypeIds once (avoid repeated infer_value_type calls)
187→    TypeId[8] arg_types;
188→    usz arg_count = args.len;
189→    if (arg_count > 8) { arg_count = 8; }
190→    for (usz a = 0; a < arg_count; a++) {
191→        arg_types[a] = infer_value_type(args[a], interp);
192→    }
193→
194→    for (usz i = 0; i < mt.entry_count; i++) {
195→        MethodEntry* entry = &mt.entries[i];
196→
197→        // Check arity
198→        if (entry.sig.param_count != args.len) continue;
199→
200→        long score = 0;
201→        bool matches = true;
202→
203→        for (usz j = 0; j < arg_count && j < entry.sig.param_count; j++) {
204→            TypeId expected = entry.sig.param_types[j];
205→
206→            // Check Val literal match FIRST (before any-type escape)
207→            if (entry.sig.has_val_literal[j]) {
208→                if (args[j] != null && args[j].tag == INT && args[j].int_val == entry.sig.val_literals[j]) {
209→                    score += 1000;  // Val match is strongest
210→                    continue;
211→                }
212→                matches = false;
213→                break;
214→            }
215→
216→            if (expected == INVALID_TYPE_ID) {
217→                // Any type — weak match
218→                score += 1;
219→                continue;
220→            }
221→
222→            TypeId actual = arg_types[j];
223→            if (actual == INVALID_TYPE_ID) {
224→                matches = false;
225→                break;
226→            }
227→
228→            if (actual == expected) {
229→                score += 100;  // Exact match
230→            } else if (interp.types.is_subtype(actual, expected)) {
231→                score += 10;   // Subtype match
232→            } else {
233→                matches = false;
234→                break;
235→            }
236→        }
237→
238→        // Enforce type constraints (e.g., ^{'T Number} requires arg's type <: Number)
239→        if (matches && entry.sig.constraint_count > 0) {
240→            for (usz c = 0; c < entry.sig.constraint_count; c++) {
241→                TypeId bound = entry.sig.constraints[c].bound_type;
242→                if (bound == INVALID_TYPE_ID) continue;  // unresolved bound — skip
243→
244→                // The constraint applies to the param with dict annotation.
245→                // Find which arg position has the constrained type variable.
246→                // For now: check ALL args against the bound — if any arg's type
247→                // is not a subtype of the bound, the constraint fails.
248→                // More precise: match param_sym to the annotation on a specific position.
249→                // We use a simple heuristic: scan for the arg position that has
250→                // INVALID_TYPE_ID param_type (the dict-annotated one)
251→                bool constraint_satisfied = false;
252→                for (usz p = 0; p < arg_count && p < entry.sig.param_count; p++) {
253→                    if (entry.sig.param_types[p] == INVALID_TYPE_ID && !entry.sig.has_val_literal[p]) {
254→                        TypeId actual = arg_types[p];
255→                        if (actual != INVALID_TYPE_ID &&
256→                            (interp.types.is_subtype(actual, bound))) {
257→                            constraint_satisfied = true;
258→                            break;
259→                        }
260→                    }
261→                }
262→                if (!constraint_satisfied) {
263→                    matches = false;
264→                    break;
265→                }
266→            }
267→        }
268→
269→        if (matches && score > best_score) {
270→            best_score = score;
271→            best_method = entry.implementation;
272→            best_count = 1;
273→        } else if (matches && score == best_score) {
274→            best_count++;
275→        }
276→    }
277→
278→    if (best_count > 1) {
279→        return raise_error(interp, "ambiguous method call: multiple methods match with equal specificity");
280→    }
281→
282→    return best_method;
283→}
