 13→fn StringVal* strval_new(usz initial_cap) {
 14→    if (initial_cap < 32) initial_cap = 32;
 15→    StringVal* sv = (StringVal*)mem::malloc(StringVal.sizeof);
 16→    sv.chars = (char*)mem::malloc(initial_cap);
