1255→/**
1256→ * (ffi-call handle "func_name" 'return-type arg1 'type1 arg2 'type2 ...)
1257→ * Variadic: minimum 3 args (handle, name, return type).
1258→ * After return type, args come in pairs: (value, type_symbol).
1259→ */
1260→fn Value* prim_ffi_call(Value*[] args, Env* env, Interp* interp) {
1261→    if (args.len < 3) {
1262→        return raise_error(interp, "ffi-call: expected at least 3 args (handle, name, return-type)");
1263→    }
1264→    // Arg 0: FFI handle
1265→    if (args[0].tag != FFI_HANDLE) {
1266→        return raise_error(interp, "ffi-call: first argument must be an ffi-handle");
1267→    }
1268→    if (args[0].ffi_val.lib_handle == null) {
1269→        return raise_error(interp, "ffi-call: handle is closed");
1270→    }
1271→    // Arg 1: function name (string)
1272→    if (args[1].tag != STRING) {
1273→        return raise_error(interp, "ffi-call: second argument must be a string (function name)");
1274→    }
1275→    // Arg 2: return type (symbol)
1276→    if (args[2].tag != SYMBOL) {
1277→        return raise_error(interp, "ffi-call: third argument must be a symbol (return type)");
1278→    }
1279→
1280→    // Look up the function (with dlsym cache)
1281→    char[] fn_name = args[1].str_val.chars[:args[1].str_val.len];
1282→    void* fn_ptr = null;
1283→    // Check cache first
1284→    for (usz ci = 0; ci < args[0].ffi_val.sym_cache_count; ci++) {
