1308→            args[0].ffi_val.sym_cache_ptrs[ci] = fn_ptr;
1309→            for (usz cj = 0; cj < fn_name.len; cj++) {
1310→                args[0].ffi_val.sym_cache_names[ci][cj] = fn_name[cj];
1311→            }
1312→            args[0].ffi_val.sym_cache_names[ci][fn_name.len] = 0;
