1155→fn bool ffi_is_double_type(char[] type_name) @inline {
1156→    return type_name.len == 6 && type_name[0] == 'd' && type_name[1] == 'o' && type_name[2] == 'u'
1157→        && type_name[3] == 'b' && type_name[4] == 'l' && type_name[5] == 'e';
1158→}
