1166→/**
1167→ * Convert a Pika value to a long based on FFI type symbol.
1168→ * Returns the value as a long suitable for passing through function pointer casts.
1169→ */
1170→fn long ffi_value_to_long(Value* val, char[] type_name, Interp* interp) {
1171→    if (type_name.len == 3 && type_name[0] == 'i' && type_name[1] == 'n' && type_name[2] == 't') {
1172→        // 'int
1173→        if (val != null && val.tag == INT) return val.int_val;
1174→        return 0;
1175→    }
1176→    if (type_name.len == 4 && type_name[0] == 's' && type_name[1] == 'i' && type_name[2] == 'z' && type_name[3] == 'e') {
1177→        // 'size
1178→        if (val != null && val.tag == INT) return val.int_val;
1179→        return 0;
1180→    }
1181→    if (type_name.len == 6 && type_name[0] == 's' && type_name[1] == 't' && type_name[2] == 'r') {
1182→        // 'string
1183→        if (val != null && val.tag == STRING) return (long)val.str_val.chars;
1184→        return 0;
1185→    }
1186→    if (type_name.len == 3 && type_name[0] == 'p' && type_name[1] == 't' && type_name[2] == 'r') {
1187→        // 'ptr
1188→        if (val != null && val.tag == FFI_HANDLE) return (long)val.ffi_val.lib_handle;
1189→        if (val != null && val.tag == INT) return val.int_val;
1190→        return 0;
1191→    }
1192→    if (ffi_is_double_type(type_name)) {
1193→        // 'double — use ffi_value_to_double() and proper double calling convention.
1194→        // This path returns 0; actual double args are handled in prim_ffi_call dispatch.
1195→        return 0;
1196→    }
1197→    return 0;
1198→}
