1200→/**
1201→ * Convert a C long result back to a Pika value based on FFI return type symbol.
1202→ */
1203→fn Value* ffi_long_to_value(long result, char[] type_name, Interp* interp) {
1204→    if (type_name.len == 3 && type_name[0] == 'i' && type_name[1] == 'n' && type_name[2] == 't') {
1205→        return make_int(interp, result);
1206→    }
1207→    if (type_name.len == 4 && type_name[0] == 's' && type_name[1] == 'i' && type_name[2] == 'z' && type_name[3] == 'e') {
1208→        return make_int(interp, result);
1209→    }
1210→    if (type_name.len == 6 && type_name[0] == 's' && type_name[1] == 't' && type_name[2] == 'r') {
1211→        // 'string — result is a char*
1212→        char* ptr = (char*)(uptr)result;
1213→        if (ptr == null) return make_nil(interp);
1214→        // Measure length
1215→        usz len = 0;
1216→        while (ptr[len] != 0) len++;
1217→        return make_string(interp, ptr[:len]);
1218→    }
1219→    if (type_name.len == 4 && type_name[0] == 'v' && type_name[1] == 'o' && type_name[2] == 'i' && type_name[3] == 'd') {
1220→        return make_nil(interp);
1221→    }
1222→    if (type_name.len == 3 && type_name[0] == 'p' && type_name[1] == 't' && type_name[2] == 'r') {
1223→        return make_int(interp, result);
1224→    }
1225→    if (ffi_is_double_type(type_name)) {
1226→        // 'double returns are handled directly in prim_ffi_call dispatch
1227→        // (proper XMM register convention). Should not reach here.
1228→        return make_double(interp, 0.0);
1229→    }
1230→    return make_nil(interp);
1231→}
