1288→                if (args[0].ffi_val.sym_cache_names[ci][cj] != fn_name[cj]) { match = false; break; }
1289→            }
1290→            if (match && args[0].ffi_val.sym_cache_names[ci][fn_name.len] != 0) match = false;
1291→        }
1292→        if (match) { fn_ptr = args[0].ffi_val.sym_cache_ptrs[ci]; break; }
1293→    }
1294→    if (fn_ptr == null) {
1295→        fn_ptr = dlsym(args[0].ffi_val.lib_handle, (ZString)args[1].str_val.chars);
1296→        if (fn_ptr == null) {
1297→            char* err = dlerror();
1298→            if (err != null) {
1299→                usz elen = 0;
1300→                while (err[elen] != 0 && elen < 200) elen++;
1301→                return raise_error(interp, err[:elen]);
1302→            }
1303→            return raise_error(interp, "ffi-call: dlsym failed");
1304→        }
1305→        // Populate cache
1306→        if (args[0].ffi_val.sym_cache_count < 64 && fn_name.len < 64) {
1307→            usz ci = args[0].ffi_val.sym_cache_count;
1308→            args[0].ffi_val.sym_cache_ptrs[ci] = fn_ptr;
1309→            for (usz cj = 0; cj < fn_name.len; cj++) {
1310→                args[0].ffi_val.sym_cache_names[ci][cj] = fn_name[cj];
1311→            }
1312→            args[0].ffi_val.sym_cache_names[ci][fn_name.len] = 0;
1313→            args[0].ffi_val.sym_cache_count++;
1314→        }
1315→    }
1316→
1317→    // Parse arg pairs: (value, type_symbol) after the first 3 args
1318→    usz remaining = args.len - 3;
1319→    if (remaining % 2 != 0) {
1320→        return raise_error(interp, "ffi-call: args after return-type must be (value type) pairs");
1321→    }
1322→    usz c_argc = remaining / 2;
1323→    if (c_argc > 6) {
