1325→    }
1326→
1327→    // Classify arg types (double vs integer)
1328→    char[][6] arg_types;
1329→    long[6] c_args;
1330→    double[6] d_args;
1331→    usz double_count = 0;
1332→    for (usz i = 0; i < c_argc; i++) {
1333→        Value* val = args[3 + i * 2];
1334→        Value* type_sym = args[3 + i * 2 + 1];
1335→        if (type_sym == null || type_sym.tag != SYMBOL) {
